    for (j = 0; j < ZOPFLI_CACHE_LENGTH; j++)
    {
        unsigned length = cache[j * 3] + 3;
        unsigned dist = cache[j * 3 + 1] + 256 * cache[j * 3 + 2];
        for (i = prevlength; i <= length; i++)
        {
            sublen[i] = dist;
        }
        if (length == maxlength)
            break;
        prevlength = length + 1;
